Pseudocode:
void moveSmallestToTop(Stack S) {
    if (S.isEmpty()) return;

    Stack tempStack = new Stack();
    double minVal = S.peek();

    // First pass: find the minimum value
    while (!S.isEmpty()) {
        double current = S.pop();
        if (current < minVal) {
            minVal = current;
        }
        tempStack.push(current);
    }

    // Restore elements to S, but skip the first occurrence of minVal
    boolean minFound = false;
    while (!tempStack.isEmpty()) {
        double current = tempStack.pop();
        if (current == minVal && !minFound) {
            minFound = true; // Skip pushing the minimum value back yet
        } else {
            S.push(current);
        }
    }

    // Elements in S are now reversed. We need to reverse them back.
    while (!S.isEmpty()) {
        tempStack.push(S.pop());
    }
    while (!tempStack.isEmpty()) {
        S.push(tempStack.pop());
    }

    // Finally, push the minimum value to the top
    S.push(minVal);
}
